'use client'
import { useSession, signOut } from 'next-auth/react'
import { useEffect, useRef, useState } from 'react'
import { useRouter } from 'next/navigation'

const MONO = "'Courier New', monospace"
const FONT = "Georgia, serif"

function Badge({ color, bg, children }: any) {
  return (
    <span style={{ fontSize: 11, fontWeight: 700, color, background: bg, padding: '3px 9px', borderRadius: 5, fontFamily: MONO, whiteSpace: 'nowrap' }}>
      {children}
    </span>
  )
}

const PRIORITY_COLOR: any = { CRITICAL: '#DC2626', HIGH: '#D97706', MEDIUM: '#2563EB', LOW: '#64748B' }
const PRIORITY_BG: any = { CRITICAL: '#FEF2F2', HIGH: '#FFFBEB', MEDIUM: '#EFF6FF', LOW: '#F8FAFC' }
const STATUS_COLOR: any = { OPEN: '#2563EB', IN_PROGRESS: '#D97706', RESOLVED: '#059669', CLOSED: '#94A3B8', ON_HOLD: '#7C3AED' }
const STATUS_BG: any = { OPEN: '#EFF6FF', IN_PROGRESS: '#FFFBEB', RESOLVED: '#ECFDF5', CLOSED: '#F8FAFC', ON_HOLD: '#F5F3FF' }
const DEPT_LABEL: any = { IT: 'IT', STUDENT_SERVICES: 'Student Services', FACILITIES: 'Facilities', HR: 'HR' }

const NAV = [
  { id: 'dashboard', label: 'Dashboard',  icon: '▦' },
  { id: 'tickets',   label: 'All Tickets', icon: '⊟' },
  { id: 'reports',   label: 'Reports',    icon: '📊' },
]

export default function DashboardPage() {
  const { data: session, status } = useSession()
  const router = useRouter()
  const [nav, setNav] = useState('dashboard')
  const [tickets, setTickets] = useState<any[]>([])
  const [stats, setStats] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [selectedTicket, setSelectedTicket] = useState<any>(null)
  const [ticketDetail, setTicketDetail] = useState<any>(null)
  const [replyMsg, setReplyMsg] = useState('')
  const [newStatus, setNewStatus] = useState('')
  const [filterStatus, setFilterStatus] = useState('')
  const [filterDept, setFilterDept] = useState('')
  const [search, setSearch] = useState('')
  const [showNewTicket, setShowNewTicket] = useState(false)
  const [newTicket, setNewTicket] = useState({ title: '', description: '', department: 'IT', priority: 'MEDIUM', categoryId: '' })
  const [submitting, setSubmitting] = useState(false)
  const [toast, setToast] = useState('')
  const [categories, setCategories] = useState<any[]>([])
  const [depts, setDepts]           = useState<any[]>([])
  const [attachFiles, setAttachFiles] = useState<File[]>([])
  const [replyFiles, setReplyFiles]   = useState<File[]>([])
  const [storageConfig, setStorageConfig] = useState<{ maxFileSizeMb: number; allowedExtensions: string[] }>({ maxFileSizeMb: 10, allowedExtensions: [] })
  const [eligibleAgents, setEligibleAgents] = useState<any[]>([])
  const [reassigning, setReassigning]       = useState(false)

  const replyRef = useRef<HTMLDivElement>(null)

  const userRole = (session as any)?.user?.role
  const userDept = (session as any)?.user?.department

  useEffect(() => {
    if (status === 'unauthenticated') router.push('/login')
    if (status === 'authenticated') {
      if (userRole && !['IT_AGENT', 'TENANT_ADMIN', 'SUPER_ADMIN'].includes(userRole)) router.push('/portal')
    }
  }, [status, session])

  useEffect(() => { if (status === 'authenticated') fetchAll() }, [status, nav])

  useEffect(() => {
    if (status === 'authenticated') {
      fetch('/api/tenant/categories?flat=true').then(r => r.json()).then(d => {
        if (d.success) setCategories((d.data ?? []).filter((c: any) => c.isActive))
      }).catch(() => {})
      fetch('/api/portal/storage-config').then(r => r.json()).then(d => {
        if (d.success) setStorageConfig(d.data)
      }).catch(() => {})
      fetch('/api/tenant/departments').then(r => r.json()).then(d => {
        if (d.success) setDepts(d.data.filter((x: any) => x.isActive))
      }).catch(() => {})
    }
  }, [status])

  const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(''), 3000) }

  async function fetchAll() {
    setLoading(true)
    try {
      // IT_AGENT: always filter by their assigned department (API also enforces this)
      const deptParam = userRole === 'IT_AGENT' && userDept
        ? `&department=${userDept}`
        : filterDept ? `&department=${filterDept}` : ''

      const tRes = await fetch(`/api/tickets?limit=50${filterStatus ? '&status=' + filterStatus : ''}${deptParam}${search ? '&search=' + search : ''}`)
      if (tRes.ok) {
        const tData = await tRes.json().catch(() => ({}))
        if (tData.success) setTickets(tData.data.tickets ?? [])
      }
    } catch (e) { console.error('tickets fetch error', e) }

    try {
      const rRes = await fetch('/api/reports')
      if (rRes.ok) {
        const rData = await rRes.json().catch(() => ({}))
        if (rData.success) setStats(rData.data)
      }
    } catch (e) { console.error('reports fetch error', e) }

    setLoading(false)
  }

  async function openTicket(t: any) {
    setSelectedTicket(t)
    setTicketDetail(null)
    setEligibleAgents([])
    setNewStatus(t.status)
    setReplyMsg('')
    if (replyRef.current) replyRef.current.innerHTML = ''
    try {
      const res  = await fetch(`/api/tickets/${t.id}`)
      const data = await res.json().catch(() => ({}))
      if (data.success) {
        setTicketDetail(data.data)
      } else {
        showToast('Error loading ticket: ' + (data.error ?? res.status))
        setTicketDetail({ ...t, messages: [], activities: [] })
      }
    } catch (e: any) {
      showToast('Error: ' + e.message)
      setTicketDetail({ ...t, messages: [], activities: [] })
    }
    // Load eligible agents for reassign dropdown (admins only)
    loadEligibleAgents(t.id)
  }

  function applyReplyFormat(format: string) {
    const editor = replyRef.current
    if (!editor) return
    editor.focus()
    if (format === 'bold')           document.execCommand('bold',                false)
    else if (format === 'italic')    document.execCommand('italic',              false)
    else if (format === 'underline') document.execCommand('underline',           false)
    else if (format === 'heading')   document.execCommand('formatBlock',         false, 'h3')
    else if (format === 'bullet')    document.execCommand('insertUnorderedList', false)
    else if (format === 'numbered')  document.execCommand('insertOrderedList',   false)
    setReplyMsg(editor.textContent ?? '')
  }

  async function sendReply() {
    const htmlBody = replyRef.current?.innerHTML ?? ''
    const textBody = replyRef.current?.textContent?.trim() ?? ''
    if (!textBody || !ticketDetail) return
    setSubmitting(true)
    const res = await fetch(`/api/tickets/${ticketDetail.id}/messages`, {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ messageBody: htmlBody, isInternal: false }),
    })
    const data = await res.json()
    if (data.success) {
      setReplyMsg('')
      if (replyRef.current) replyRef.current.innerHTML = ''
      if (replyFiles.length > 0) {
        for (const file of replyFiles) {
          const fd = new FormData()
          fd.append('file', file)
          fd.append('messageId', data.data.id)
          await fetch(`/api/tickets/${ticketDetail.id}/attachments`, { method: 'POST', body: fd }).catch(() => {})
        }
        setReplyFiles([])
        // Refresh to show attachments on the message
        const refreshRes = await fetch(`/api/tickets/${ticketDetail.id}`)
        const refreshData = await refreshRes.json().catch(() => ({}))
        if (refreshData.success) setTicketDetail(refreshData.data)
      } else {
        setTicketDetail((prev: any) => ({ ...prev, messages: [...prev.messages, data.data] }))
      }
      showToast('Reply sent.')
    } else if (data.code === 'ASSIGNMENT_REQUIRED') {
      showToast('You must assign this ticket to yourself before replying.')
    } else {
      showToast('Error: ' + (data.error ?? 'Could not send reply'))
    }
    setSubmitting(false)
  }

  function addReplyFiles(files: FileList | null) {
    if (!files) return
    Array.from(files).forEach(file => {
      const ext = file.name.split('.').pop()?.toLowerCase() ?? ''
      if (storageConfig.allowedExtensions.length > 0 && !storageConfig.allowedExtensions.includes(ext)) {
        showToast(`.${ext} is not an allowed file type`); return
      }
      if (file.size > storageConfig.maxFileSizeMb * 1024 * 1024) {
        showToast(`${file.name} exceeds the ${storageConfig.maxFileSizeMb} MB limit`); return
      }
      setReplyFiles(prev => [...prev, file])
    })
  }

  async function assignSelf() {
    if (!ticketDetail) return
    setSubmitting(true)
    const res = await fetch(`/api/tickets/${ticketDetail.id}`, {
      method: 'PATCH', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ assigneeId: (session?.user as any)?.id }),
    })
    const data = await res.json()
    if (data.success) {
      setTicketDetail((prev: any) => ({
        ...prev,
        assigneeId: (session?.user as any)?.id,
        assignee: data.data.assignee,
        canReply: true,
        status: data.data.status,
      }))
      setSelectedTicket((prev: any) => ({ ...prev, assigneeId: (session?.user as any)?.id, status: data.data.status }))
      setTickets(prev => prev.map(t => t.id === ticketDetail.id ? { ...t, assigneeId: (session?.user as any)?.id, status: data.data.status } : t))
      setNewStatus(data.data.status)
      showToast('Ticket assigned to you!')
    } else {
      showToast('Error: ' + (data.error ?? 'Could not assign ticket'))
    }
    setSubmitting(false)
  }

  async function loadEligibleAgents(ticketId: string) {
    const res = await fetch(`/api/tickets/${ticketId}/eligible-agents`)
    const data = await res.json()
    if (data.success) setEligibleAgents(data.data)
  }

  async function reassignAgent(agentId: string | null) {
    if (!ticketDetail) return
    setReassigning(true)
    const res = await fetch(`/api/tickets/${ticketDetail.id}`, {
      method: 'PATCH', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ assigneeId: agentId }),
    })
    const data = await res.json()
    if (data.success) {
      setTicketDetail((prev: any) => ({
        ...prev,
        assigneeId: data.data.assigneeId,
        assignee: data.data.assignee,
        canReply: agentId === (session?.user as any)?.id ? true : prev.canReply,
        status: data.data.status,
      }))
      setSelectedTicket((prev: any) => ({ ...prev, assigneeId: data.data.assigneeId, status: data.data.status }))
      setTickets(prev => prev.map(t => t.id === ticketDetail.id ? { ...t, assigneeId: data.data.assigneeId, status: data.data.status } : t))
      setNewStatus(data.data.status)
      showToast(agentId ? `Reassigned to ${data.data.assignee?.name ?? 'agent'}` : 'Ticket unassigned')
    } else {
      showToast('Error: ' + (data.error ?? 'Could not reassign ticket'))
    }
    setReassigning(false)
  }

  async function updateStatus(status: string) {
    if (!ticketDetail) return
    const res = await fetch(`/api/tickets/${ticketDetail.id}`, {
      method: 'PATCH', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status }),
    })
    const data = await res.json()
    if (data.success) {
      setTicketDetail((prev: any) => ({ ...prev, status }))
      setSelectedTicket((prev: any) => ({ ...prev, status }))
      setTickets(prev => prev.map(t => t.id === ticketDetail.id ? { ...t, status } : t))
      setNewStatus(status)
      showToast(`Status updated to ${status.replace('_', ' ')}`)
    }
  }

  async function updatePriority(priority: string) {
    if (!ticketDetail) return
    const res = await fetch(`/api/tickets/${ticketDetail.id}`, {
      method: 'PATCH', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ priority }),
    })
    const data = await res.json()
    if (data.success) {
      setTicketDetail((prev: any) => ({ ...prev, priority }))
      setSelectedTicket((prev: any) => ({ ...prev, priority }))
      setTickets(prev => prev.map(t => t.id === ticketDetail.id ? { ...t, priority } : t))
      showToast(`Priority updated to ${priority}`)
    } else {
      showToast('Error: ' + (data.error ?? 'Could not update priority'))
    }
  }

  async function submitNewTicket() {
    if (!newTicket.title || !newTicket.description) return
    setSubmitting(true)
    try {
      const payload: any = { ...newTicket }
      if (!payload.categoryId) delete payload.categoryId
      const res = await fetch('/api/tickets', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      })
      const data = await res.json().catch(() => ({}))
      if (data.success) {
        if (attachFiles.length > 0) {
          for (const file of attachFiles) {
            const fd = new FormData()
            fd.append('file', file)
            await fetch(`/api/tickets/${data.data.id}/attachments`, { method: 'POST', body: fd }).catch(() => {})
          }
        }
        setTickets(prev => [data.data, ...prev])
        setShowNewTicket(false)
        setNewTicket({ title: '', description: '', department: 'IT', priority: 'MEDIUM', categoryId: '' })
        setAttachFiles([])
        showToast('Ticket created successfully!')
      } else {
        showToast('Error: ' + (data.error ?? 'Could not create ticket'))
      }
    } catch (e: any) { showToast('Error: ' + e.message) }
    setSubmitting(false)
  }

  const filteredTickets = tickets.filter(t => {
    if (filterStatus && t.status !== filterStatus) return false
    if (userRole === 'IT_AGENT') return true // dept already filtered by API
    if (filterDept && t.department !== filterDept) return false
    if (search && !t.title.toLowerCase().includes(search.toLowerCase()) && !t.submitter?.name.toLowerCase().includes(search.toLowerCase())) return false
    return true
  })

  if (status === 'loading') return <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', height: '100vh', fontFamily: FONT }}>Loading…</div>

  return (
    <div style={{ display: 'flex', height: '100vh', fontFamily: FONT, background: '#F8FAFC', overflow: 'hidden' }}>
      <style>{`
        [contenteditable] h3 { font-size:15px; font-weight:700; margin:6px 0 3px; }
        [contenteditable] ul { margin:4px 0 4px 18px; padding:0; list-style:disc; }
        [contenteditable] ol { margin:4px 0 4px 18px; padding:0; list-style:decimal; }
        [contenteditable] li { margin:2px 0; }
        [contenteditable] strong { font-weight:700; }
        [contenteditable] em { font-style:italic; }
      `}</style>

      {/* Sidebar */}
      <div style={{ width: 220, background: '#0F172A', display: 'flex', flexDirection: 'column', flexShrink: 0 }}>
        <div style={{ padding: '24px 20px 20px', borderBottom: '1px solid #1E293B' }}>
          <div style={{ fontSize: 22, fontWeight: 900, color: '#F1F5F9' }}>Edu<span style={{ color: '#3B82F6' }}>Desk</span></div>
          <div style={{ fontSize: 10, color: '#475569', fontFamily: MONO, marginTop: 2, letterSpacing: 1 }}>IT HELPDESK</div>
        </div>
        <nav style={{ flex: 1, padding: '12px 10px' }}>
          {NAV.map(item => (
            <button key={item.id} onClick={() => setNav(item.id)} style={{
              display: 'flex', alignItems: 'center', gap: 10, width: '100%', padding: '10px 12px',
              borderRadius: 8, border: 'none', cursor: 'pointer', marginBottom: 2, textAlign: 'left',
              background: nav === item.id ? '#1E3A5F' : 'transparent',
              color: nav === item.id ? '#93C5FD' : '#64748B',
            }}>
              <span style={{ fontSize: 16 }}>{item.icon}</span>
              <span style={{ fontSize: 13, fontWeight: nav === item.id ? 700 : 400 }}>{item.label}</span>
            </button>
          ))}
        </nav>
        <div style={{ padding: '16px 20px', borderTop: '1px solid #1E293B' }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: '#E2E8F0', marginBottom: 2 }}>{session?.user?.name}</div>
          <div style={{ fontSize: 10, color: '#475569', fontFamily: MONO, marginBottom: 2 }}>{userRole}</div>
          {userDept && <div style={{ fontSize: 10, color: '#334155', fontFamily: MONO, marginBottom: 10 }}>{userDept}</div>}
          <button onClick={() => signOut({ callbackUrl: '/login' })} style={{ fontSize: 11, color: '#64748B', background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}>Sign out</button>
          <div style={{ fontSize: 9, color: '#1E293B', fontFamily: MONO, marginTop: 10 }}>Powered by CloudTitans © 2026 v3.0</div>
        </div>
      </div>

      {/* Main */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Topbar */}
        <div style={{ background: 'white', borderBottom: '1px solid #E2E8F0', padding: '14px 28px', display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexShrink: 0 }}>
          <div>
            <div style={{ fontSize: 18, fontWeight: 800, color: '#0F172A' }}>
              {nav === 'dashboard' && 'Overview Dashboard'}
              {nav === 'tickets' && 'All Tickets'}
              {nav === 'reports' && 'Reports & Analytics'}
            </div>
            <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO }}>
              {new Date().toDateString()}
              {userRole === 'IT_AGENT' && userDept && (
                <span style={{ marginLeft: 10, color: '#7C3AED', fontWeight: 700 }}>· {DEPT_LABEL[userDept] ?? userDept} Dept Only</span>
              )}
            </div>
          </div>
          <button onClick={() => setShowNewTicket(true)} style={{ padding: '9px 18px', background: '#2563EB', color: 'white', border: 'none', borderRadius: 8, fontSize: 13, fontWeight: 700, cursor: 'pointer' }}>
            + New Ticket
          </button>
        </div>

        {/* Content */}
        <div style={{ flex: 1, overflowY: 'auto', padding: '24px 28px' }}>

          {/* DASHBOARD */}
          {nav === 'dashboard' && stats && (
            <div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 16, marginBottom: 24 }}>
                {[
                  { label: 'Open', value: stats.summary.totalOpen, color: '#2563EB', icon: '🎫' },
                  { label: 'In Progress', value: stats.summary.totalInProgress, color: '#D97706', icon: '⏳' },
                  { label: 'Resolved Today', value: stats.summary.resolvedToday, color: '#059669', icon: '✅' },
                  { label: 'Avg Resolution', value: `${stats.summary.avgResolutionHours}h`, color: '#7C3AED', icon: '⏱' },
                ].map(s => (
                  <div key={s.label} style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, padding: '20px 22px', borderTop: `3px solid ${s.color}` }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO }}>{s.label.toUpperCase()}</div>
                      <span style={{ color: s.color }}>{s.icon}</span>
                    </div>
                    <div style={{ fontSize: 34, fontWeight: 900, color: '#0F172A', marginTop: 8 }}>{s.value}</div>
                  </div>
                ))}
              </div>

              <div style={{ display: 'grid', gridTemplateColumns: '1.6fr 1fr', gap: 20 }}>
                <div style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, overflow: 'hidden' }}>
                  <div style={{ padding: '16px 20px', borderBottom: '1px solid #F1F5F9', display: 'flex', justifyContent: 'space-between' }}>
                    <div style={{ fontWeight: 800, fontSize: 14 }}>Recent Tickets</div>
                    <button onClick={() => setNav('tickets')} style={{ fontSize: 12, color: '#2563EB', border: 'none', background: 'none', cursor: 'pointer' }}>View all →</button>
                  </div>
                  {tickets.slice(0, 6).map(t => (
                    <div key={t.id} onClick={() => openTicket(t)} style={{ padding: '12px 20px', borderBottom: '1px solid #F8FAFC', display: 'flex', alignItems: 'center', gap: 12, cursor: 'pointer' }}
                      onMouseEnter={e => (e.currentTarget.style.background = '#F8FAFC')}
                      onMouseLeave={e => (e.currentTarget.style.background = 'white')}>
                      <div style={{ width: 32, height: 32, borderRadius: '50%', background: '#DBEAFE', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 12, fontWeight: 800, color: '#1D4ED8', flexShrink: 0 }}>
                        {t.submitter?.name?.[0] ?? '?'}
                      </div>
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: 13, fontWeight: 600, color: '#1E293B', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{t.title}</div>
                        <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO }}>{t.submitter?.name} · {DEPT_LABEL[t.department]}</div>
                      </div>
                      <div style={{ display: 'flex', gap: 6, flexShrink: 0 }}>
                        <Badge color={PRIORITY_COLOR[t.priority]} bg={PRIORITY_BG[t.priority]}>{t.priority}</Badge>
                        <Badge color={STATUS_COLOR[t.status]} bg={STATUS_BG[t.status]}>{t.status.replace('_', ' ')}</Badge>
                      </div>
                    </div>
                  ))}
                </div>

                <div style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, padding: 20 }}>
                  <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 20 }}>By Department</div>
                  {stats.byDepartment.map((d: any) => {
                    const total = stats.byDepartment.reduce((s: number, x: any) => s + x._count, 0)
                    const pct = total > 0 ? Math.round((d._count / total) * 100) : 0
                    const colors: any = { IT: '#2563EB', STUDENT_SERVICES: '#7C3AED', FACILITIES: '#059669', HR: '#D97706' }
                    return (
                      <div key={d.department} style={{ marginBottom: 16 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 13, marginBottom: 5 }}>
                          <span style={{ fontWeight: 600 }}>{DEPT_LABEL[d.department]}</span>
                          <span style={{ color: '#94A3B8', fontFamily: MONO }}>{d._count} · {pct}%</span>
                        </div>
                        <div style={{ height: 7, borderRadius: 4, background: '#F1F5F9' }}>
                          <div style={{ height: '100%', borderRadius: 4, background: colors[d.department] ?? '#94A3B8', width: `${pct}%` }} />
                        </div>
                      </div>
                    )
                  })}
                  <div style={{ marginTop: 20, paddingTop: 16, borderTop: '1px solid #F1F5F9' }}>
                    <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO, marginBottom: 8 }}>THIS MONTH</div>
                    <div style={{ fontSize: 28, fontWeight: 900, color: '#0F172A' }}>{stats.summary.totalThisMonth}</div>
                    <div style={{ fontSize: 12, color: '#64748B' }}>total tickets submitted</div>
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* TICKETS */}
          {nav === 'tickets' && (
            <div>
              <div style={{ display: 'flex', gap: 10, marginBottom: 20, flexWrap: 'wrap', alignItems: 'center' }}>
                <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Search tickets…"
                  style={{ padding: '9px 14px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none', width: 220, background: 'white' }} />
                {['', 'OPEN', 'IN_PROGRESS', 'RESOLVED', 'CLOSED'].map(s => (
                  <button key={s} onClick={() => setFilterStatus(s)} style={{ padding: '8px 12px', borderRadius: 8, border: `1px solid ${filterStatus === s ? '#2563EB' : '#E2E8F0'}`, background: filterStatus === s ? '#EFF6FF' : 'white', color: filterStatus === s ? '#2563EB' : '#64748B', fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>
                    {s || 'All'}
                  </button>
                ))}
                {/* Department filter — hidden for IT_AGENT (they only see their dept) */}
                {userRole !== 'IT_AGENT' && [{ department: '', label: 'All Depts' }, ...depts].map((d: any) => (
                  <button key={d.department} onClick={() => setFilterDept(d.department)} style={{ padding: '8px 12px', borderRadius: 8, border: `1px solid ${filterDept === d.department ? '#7C3AED' : '#E2E8F0'}`, background: filterDept === d.department ? '#F5F3FF' : 'white', color: filterDept === d.department ? '#7C3AED' : '#64748B', fontSize: 11, fontWeight: 600, cursor: 'pointer' }}>
                    {d.label}
                  </button>
                ))}
                {userRole === 'IT_AGENT' && userDept && (
                  <span style={{ padding: '8px 12px', borderRadius: 8, border: '1px solid #7C3AED', background: '#F5F3FF', color: '#7C3AED', fontSize: 11, fontWeight: 700 }}>
                    {DEPT_LABEL[userDept] ?? userDept} Only
                  </span>
                )}
              </div>

              <div style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, overflow: 'hidden' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 160px 120px 110px 110px', padding: '10px 20px', background: '#F8FAFC', borderBottom: '1px solid #E2E8F0' }}>
                  {['Ticket', 'Submitted By', 'Department', 'Priority', 'Status'].map(h => (
                    <div key={h} style={{ fontSize: 11, fontWeight: 700, color: '#94A3B8', fontFamily: MONO }}>{h}</div>
                  ))}
                </div>
                {loading && <div style={{ padding: 30, textAlign: 'center', color: '#94A3B8' }}>Loading…</div>}
                {!loading && filteredTickets.length === 0 && <div style={{ padding: 30, textAlign: 'center', color: '#94A3B8' }}>No tickets found.</div>}
                {filteredTickets.map(t => (
                  <div key={t.id} onClick={() => openTicket(t)} style={{ display: 'grid', gridTemplateColumns: '1fr 160px 120px 110px 110px', padding: '13px 20px', borderBottom: '1px solid #F8FAFC', cursor: 'pointer', alignItems: 'center' }}
                    onMouseEnter={e => (e.currentTarget.style.background = '#F8FAFC')}
                    onMouseLeave={e => (e.currentTarget.style.background = 'white')}>
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600, color: '#1E293B' }}>{t.title}</div>
                      <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO }}>#{t.ticketNumber} · {new Date(t.createdAt).toLocaleDateString()}</div>
                    </div>
                    <div style={{ fontSize: 12, color: '#475569' }}>{t.submitter?.name}</div>
                    <Badge color='#475569' bg='#F1F5F9'>{depts.find((d: any) => d.department === t.department)?.label ?? t.department}</Badge>
                    <Badge color={PRIORITY_COLOR[t.priority]} bg={PRIORITY_BG[t.priority]}>{t.priority}</Badge>
                    <Badge color={STATUS_COLOR[t.status]} bg={STATUS_BG[t.status]}>{t.status.replace('_', ' ')}</Badge>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* REPORTS */}
          {nav === 'reports' && stats && (
            <div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 16, marginBottom: 24 }}>
                {[
                  { label: 'Total This Month', value: stats.summary.totalThisMonth, color: '#2563EB' },
                  { label: 'Avg Resolution (hrs)', value: stats.summary.avgResolutionHours, color: '#059669' },
                  { label: 'SLA Breaches', value: stats.summary.slaBreaches, color: '#DC2626' },
                ].map(s => (
                  <div key={s.label} style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, padding: 22, borderLeft: `4px solid ${s.color}` }}>
                    <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO, marginBottom: 8 }}>{s.label.toUpperCase()}</div>
                    <div style={{ fontSize: 36, fontWeight: 900, color: '#0F172A' }}>{s.value}</div>
                  </div>
                ))}
              </div>

              <div style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, padding: 24, marginBottom: 20 }}>
                <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 20 }}>Tickets by Status</div>
                <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
                  {stats.byStatus.map((s: any) => (
                    <div key={s.status} style={{ background: STATUS_BG[s.status] ?? '#F8FAFC', border: `1px solid ${STATUS_COLOR[s.status] ?? '#94A3B8'}44`, borderRadius: 10, padding: '14px 20px', minWidth: 120, textAlign: 'center' }}>
                      <div style={{ fontSize: 28, fontWeight: 900, color: STATUS_COLOR[s.status] ?? '#94A3B8' }}>{s._count}</div>
                      <div style={{ fontSize: 11, color: '#64748B', fontFamily: MONO, marginTop: 4 }}>{s.status.replace('_', ' ')}</div>
                    </div>
                  ))}
                </div>
              </div>

              <div style={{ background: 'white', border: '1px solid #E2E8F0', borderRadius: 12, padding: 24 }}>
                <div style={{ fontWeight: 800, fontSize: 14, marginBottom: 20 }}>Agent Performance</div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 12 }}>
                  {stats.agentStats.map((a: any) => (
                    <div key={a.id} style={{ background: '#F8FAFC', borderRadius: 10, padding: 16 }}>
                      <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 8 }}>{a.name}</div>
                      <div style={{ display: 'flex', gap: 10 }}>
                        <div style={{ background: '#EFF6FF', borderRadius: 7, padding: '8px 12px', flex: 1, textAlign: 'center' }}>
                          <div style={{ fontSize: 20, fontWeight: 900, color: '#2563EB' }}>{a.openTickets}</div>
                          <div style={{ fontSize: 10, color: '#94A3B8', fontFamily: MONO }}>OPEN</div>
                        </div>
                        <div style={{ background: '#ECFDF5', borderRadius: 7, padding: '8px 12px', flex: 1, textAlign: 'center' }}>
                          <div style={{ fontSize: 20, fontWeight: 900, color: '#059669' }}>{a.totalAssigned}</div>
                          <div style={{ fontSize: 10, color: '#94A3B8', fontFamily: MONO }}>TOTAL</div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

        </div>
      </div>

      {/* Ticket Detail Drawer */}
      {selectedTicket && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(15,23,42,0.4)', zIndex: 100, display: 'flex', justifyContent: 'flex-end' }} onClick={() => { setSelectedTicket(null); setTicketDetail(null); setReplyFiles([]); setReplyMsg(''); if (replyRef.current) replyRef.current.innerHTML = '' }}>
          <div onClick={e => e.stopPropagation()} style={{ width: 480, height: '100%', background: 'white', boxShadow: '-8px 0 40px rgba(0,0,0,0.12)', display: 'flex', flexDirection: 'column' }}>
            <div style={{ padding: '22px 26px', borderBottom: '1px solid #F1F5F9' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <div style={{ flex: 1, paddingRight: 12 }}>
                  <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO, marginBottom: 4 }}>#{selectedTicket.ticketNumber} · {depts.find((d: any) => d.department === selectedTicket.department)?.label ?? selectedTicket.department}</div>
                  <div style={{ fontSize: 16, fontWeight: 700, color: '#0F172A', lineHeight: 1.3 }}>{selectedTicket.title}</div>
                  <div style={{ display: 'flex', gap: 6, marginTop: 10, alignItems: 'center', flexWrap: 'wrap' }}>
                    {/* Priority selector — agents + admins can change it */}
                    {ticketDetail && ['IT_AGENT','TENANT_ADMIN','SUPER_ADMIN'].includes(userRole) && (ticketDetail.canReply || ['TENANT_ADMIN','SUPER_ADMIN'].includes(userRole)) ? (
                      <select value={ticketDetail?.priority ?? selectedTicket.priority}
                        onChange={e => updatePriority(e.target.value)}
                        style={{ fontSize: 11, fontWeight: 700, border: `1px solid ${PRIORITY_COLOR[ticketDetail?.priority ?? selectedTicket.priority]}`, borderRadius: 5, padding: '3px 8px', background: PRIORITY_BG[ticketDetail?.priority ?? selectedTicket.priority], color: PRIORITY_COLOR[ticketDetail?.priority ?? selectedTicket.priority], cursor: 'pointer', fontFamily: MONO }}>
                        {['CRITICAL','HIGH','MEDIUM','LOW'].map(p => <option key={p} value={p}>{p}</option>)}
                      </select>
                    ) : (
                      <Badge color={PRIORITY_COLOR[selectedTicket.priority]} bg={PRIORITY_BG[selectedTicket.priority]}>{selectedTicket.priority}</Badge>
                    )}
                    <Badge color={STATUS_COLOR[newStatus]} bg={STATUS_BG[newStatus]}>{newStatus.replace('_', ' ')}</Badge>
                  </div>
                </div>
                <button onClick={() => { setSelectedTicket(null); setTicketDetail(null); setReplyFiles([]); setReplyMsg(''); if (replyRef.current) replyRef.current.innerHTML = '' }} style={{ border: 'none', background: '#F1F5F9', borderRadius: 8, width: 32, height: 32, cursor: 'pointer', fontSize: 18, color: '#64748B' }}>×</button>
              </div>
            </div>

            <div style={{ flex: 1, overflowY: 'auto', padding: '18px 26px' }}>
              {ticketDetail ? (
                <>
                  <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14, marginBottom: 20 }}>
                    {[
                      { l: 'Submitted by', v: ticketDetail.submitter?.name },
                      { l: 'Role', v: ticketDetail.submitter?.role?.replace('_', ' ') },
                      { l: 'Created', v: new Date(ticketDetail.createdAt).toLocaleString() },
                    ].map(f => (
                      <div key={f.l}>
                        <div style={{ fontSize: 10, color: '#94A3B8', fontFamily: MONO, marginBottom: 3 }}>{f.l.toUpperCase()}</div>
                        <div style={{ fontSize: 13, fontWeight: 600 }}>{f.v}</div>
                      </div>
                    ))}
                    {/* Assign to — dropdown for admins, static for agents */}
                    <div>
                      <div style={{ fontSize: 10, color: '#94A3B8', fontFamily: MONO, marginBottom: 3 }}>ASSIGNED TO</div>
                      {['TENANT_ADMIN', 'SUPER_ADMIN'].includes(userRole) ? (
                        <select
                          value={ticketDetail.assigneeId ?? ''}
                          disabled={reassigning}
                          onChange={e => reassignAgent(e.target.value || null)}
                          style={{ fontSize: 12, fontWeight: 600, border: '1px solid #E2E8F0', borderRadius: 6, padding: '4px 8px', background: 'white', cursor: 'pointer', width: '100%', opacity: reassigning ? 0.6 : 1 }}
                        >
                          <option value=''>— Unassigned —</option>
                          {eligibleAgents.map(a => (
                            <option key={a.id} value={a.id}>{a.name}</option>
                          ))}
                        </select>
                      ) : (
                        <div style={{ fontSize: 13, fontWeight: 600 }}>{ticketDetail.assignee?.name ?? 'Unassigned'}</div>
                      )}
                    </div>
                  </div>
                  <div style={{ background: '#F8FAFC', borderRadius: 8, padding: 14, marginBottom: 10, fontSize: 13, color: '#475569', lineHeight: 1.6 }}>
                    <div dangerouslySetInnerHTML={{ __html: ticketDetail.description }} />
                    {/* Ticket-level attachments (submitted with the ticket, no messageId) */}
                    {ticketDetail?.attachments?.filter((a: any) => !a.messageId).length > 0 && (
                      <div style={{ marginTop: 10, paddingTop: 10, borderTop: '1px solid #E2E8F0', display: 'flex', flexDirection: 'column', gap: 4 }}>
                        <div style={{ fontSize: 10, color: '#94A3B8', fontFamily: MONO, marginBottom: 4 }}>ATTACHMENTS</div>
                        {ticketDetail.attachments.filter((a: any) => !a.messageId).map((att: any) => (
                          <a key={att.id} href={att.downloadUrl} target='_blank' rel='noreferrer'
                            style={{ fontSize: 11, color: '#2563EB', fontFamily: MONO, textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 4 }}>
                            📎 {att.fileName} <span style={{ color: '#94A3B8' }}>({(att.sizeBytes / 1024).toFixed(0)} KB)</span>
                          </a>
                        ))}
                      </div>
                    )}
                  </div>

                  <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO, marginBottom: 10 }}>MESSAGES</div>
                  {ticketDetail.messages?.map((m: any) => (
                    <div key={m.id} style={{ marginBottom: 14, display: 'flex', flexDirection: 'column', alignItems: m.author?.role === 'STUDENT' || m.author?.role === 'TEACHER' || m.author?.role === 'STAFF' ? 'flex-start' : 'flex-end' }}>
                      <div style={{ fontSize: 11, color: '#94A3B8', fontFamily: MONO, marginBottom: 3 }}>{m.author?.name} · {new Date(m.createdAt).toLocaleTimeString()}{m.isInternal ? ' · INTERNAL' : ''}</div>
                      <div style={{ maxWidth: '85%', padding: '10px 14px', borderRadius: 10, background: m.isInternal ? '#FFFBEB' : m.author?.role === 'IT_AGENT' || m.author?.role === 'IT_ADMIN' ? '#EFF6FF' : '#F1F5F9', fontSize: 13, color: '#334155', lineHeight: 1.5, border: m.isInternal ? '1px solid #FDE68A' : 'none' }}>
                        <div dangerouslySetInnerHTML={{ __html: m.body }} />
                        {m.attachments?.length > 0 && (
                          <div style={{ marginTop: 8, display: 'flex', flexDirection: 'column', gap: 4, borderTop: '1px solid rgba(0,0,0,0.06)', paddingTop: 8 }}>
                            {m.attachments.map((att: any) => (
                              <a key={att.id} href={att.downloadUrl} target='_blank' rel='noreferrer'
                                style={{ fontSize: 11, color: '#2563EB', fontFamily: MONO, textDecoration: 'none', display: 'flex', alignItems: 'center', gap: 4 }}>
                                📎 {att.fileName}
                              </a>
                            ))}
                          </div>
                        )}
                      </div>
                    </div>
                  ))}
                </>
              ) : (
                <div style={{ textAlign: 'center', color: '#94A3B8', paddingTop: 40 }}>Loading…</div>
              )}
            </div>

            <div style={{ padding: '14px 26px', borderTop: '1px solid #F1F5F9' }}>
              {/* Assign-to-me banner: shown to IT_AGENT when ticket is not assigned to them */}
              {ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT' && (
                <div style={{ background: '#FFF7ED', border: '1px solid #FED7AA', borderRadius: 8, padding: '10px 14px', marginBottom: 12, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span style={{ fontSize: 13, color: '#C2410C' }}>Assign this ticket to yourself before replying</span>
                  <button onClick={assignSelf} disabled={submitting}
                    style={{ padding: '6px 14px', background: '#EA580C', color: 'white', border: 'none', borderRadius: 6, fontSize: 12, fontWeight: 700, cursor: submitting ? 'not-allowed' : 'pointer', opacity: submitting ? 0.6 : 1 }}>
                    {submitting ? '…' : 'Assign to me'}
                  </button>
                </div>
              )}
              {/* WYSIWYG reply editor */}
              {(() => {
                const locked = !!(ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT')
                return (
                  <div style={{ opacity: locked ? 0.4 : 1, pointerEvents: locked ? 'none' : 'auto' }}>
                    {/* Toolbar */}
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, padding: '5px 8px', background: '#F8FAFC', borderRadius: '8px 8px 0 0', border: '1px solid #E2E8F0', borderBottom: 'none' }}>
                      {[
                        { fmt: 'bold',     label: 'B',       title: 'Bold',          style: { fontWeight: 900 } },
                        { fmt: 'italic',   label: 'I',       title: 'Italic',        style: { fontStyle: 'italic' as const } },
                        { fmt: 'underline',label: 'U',       title: 'Underline',     style: { textDecoration: 'underline' as const } },
                        { fmt: 'heading',  label: 'H₃',      title: 'Heading',       style: { fontWeight: 700, fontSize: 11 } },
                        { fmt: 'bullet',   label: '• List',  title: 'Bullet list',   style: {} },
                        { fmt: 'numbered', label: '1. List', title: 'Numbered list', style: {} },
                      ].map(btn => (
                        <button key={btn.fmt} type='button' title={btn.title}
                          onMouseDown={e => { e.preventDefault(); applyReplyFormat(btn.fmt) }}
                          style={{ padding: '3px 9px', border: '1px solid #E2E8F0', borderRadius: 5, background: 'white', cursor: 'pointer', fontSize: 12, fontFamily: MONO, ...btn.style }}>
                          {btn.label}
                        </button>
                      ))}
                    </div>
                    {/* contentEditable area */}
                    <div style={{ position: 'relative' }}>
                      {!replyMsg && (
                        <div style={{ position: 'absolute', top: '10px', left: '13px', color: '#CBD5E1', fontSize: 13, fontFamily: FONT, pointerEvents: 'none', userSelect: 'none' }}>
                          Reply to user or add internal note…
                        </div>
                      )}
                      <div
                        ref={replyRef}
                        contentEditable={!locked}
                        suppressContentEditableWarning
                        onInput={() => setReplyMsg(replyRef.current?.textContent ?? '')}
                        style={{ minHeight: 90, padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: '0 0 8px 8px', fontSize: 13, fontFamily: FONT, outline: 'none', lineHeight: 1.7, wordBreak: 'break-word', overflowY: 'auto', boxSizing: 'border-box' as const, marginBottom: 8 }}
                      />
                    </div>
                  </div>
                )
              })()}
              {/* Selected reply files */}
              {replyFiles.length > 0 && (
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 5, marginBottom: 8 }}>
                  {replyFiles.map((f, i) => (
                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 4, background: '#EFF6FF', border: '1px solid #BFDBFE', borderRadius: 5, padding: '3px 8px' }}>
                      <span style={{ fontSize: 11, color: '#2563EB', fontFamily: MONO, maxWidth: 130, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>📎 {f.name}</span>
                      <button onClick={() => setReplyFiles(prev => prev.filter((_, j) => j !== i))}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94A3B8', fontSize: 14, padding: '0 2px', lineHeight: 1 }}>×</button>
                    </div>
                  ))}
                </div>
              )}
              <div style={{ display: 'flex', gap: 8 }}>
                {/* File attach button */}
                <label title={`Attach file (max ${storageConfig.maxFileSizeMb} MB)`}
                  style={{ padding: '9px 10px', background: '#F1F5F9', border: '1px solid #E2E8F0', borderRadius: 7, cursor: (ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT') ? 'not-allowed' : 'pointer', fontSize: 14, color: '#64748B', display: 'flex', alignItems: 'center', opacity: (ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT') ? 0.4 : 1 }}>
                  📎
                  <input type='file' multiple
                    disabled={!!(ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT')}
                    accept={storageConfig.allowedExtensions.map((e: string) => `.${e}`).join(',')}
                    onChange={e => { addReplyFiles(e.target.files); e.target.value = '' }}
                    style={{ display: 'none' }} />
                </label>
                <button onClick={sendReply} disabled={submitting || !replyMsg.trim() || !!(ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT')} style={{ flex: 1, padding: '9px 0', background: '#2563EB', color: 'white', border: 'none', borderRadius: 7, fontSize: 12, fontWeight: 700, cursor: 'pointer', opacity: (!replyMsg.trim() || (ticketDetail && !ticketDetail.canReply && userRole === 'IT_AGENT')) ? 0.5 : 1 }}>Send Reply</button>
                {['IN_PROGRESS', 'RESOLVED', 'CLOSED'].filter(s => s !== newStatus).map(s => (
                  <button key={s} onClick={() => updateStatus(s)} style={{ padding: '9px 12px', borderRadius: 7, border: `1px solid ${STATUS_COLOR[s]}`, background: STATUS_BG[s], color: STATUS_COLOR[s], fontSize: 11, fontWeight: 700, cursor: 'pointer', whiteSpace: 'nowrap' }}>
                    → {s.replace('_', ' ')}
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* New Ticket Modal */}
      {showNewTicket && (
        <div style={{ position: 'fixed', inset: 0, background: 'rgba(15,23,42,0.4)', zIndex: 100, display: 'flex', alignItems: 'center', justifyContent: 'center' }} onClick={() => setShowNewTicket(false)}>
          <div onClick={e => e.stopPropagation()} style={{ width: 480, background: 'white', borderRadius: 16, padding: 32, boxShadow: '0 24px 60px rgba(0,0,0,0.15)' }}>
            <div style={{ fontSize: 18, fontWeight: 800, marginBottom: 20 }}>Create New Ticket</div>
            {[
              { label: 'TITLE', key: 'title', type: 'text', placeholder: 'Describe the issue briefly…' },
              { label: 'DESCRIPTION', key: 'description', type: 'textarea', placeholder: 'Full details of the issue…' },
            ].map(f => (
              <div key={f.key} style={{ marginBottom: 14 }}>
                <div style={{ fontSize: 11, fontFamily: MONO, color: '#94A3B8', marginBottom: 5 }}>{f.label}</div>
                {f.type === 'textarea' ? (
                  <textarea value={(newTicket as any)[f.key]} onChange={e => setNewTicket({ ...newTicket, [f.key]: e.target.value })} placeholder={f.placeholder} rows={3}
                    style={{ width: '100%', padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none', resize: 'vertical', boxSizing: 'border-box' }} />
                ) : (
                  <input value={(newTicket as any)[f.key]} onChange={e => setNewTicket({ ...newTicket, [f.key]: e.target.value })} placeholder={f.placeholder}
                    style={{ width: '100%', padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none', boxSizing: 'border-box' }} />
                )}
              </div>
            ))}
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 14 }}>
              <div>
                <div style={{ fontSize: 11, fontFamily: MONO, color: '#94A3B8', marginBottom: 5 }}>DEPARTMENT</div>
                <select value={newTicket.department}
                  onChange={e => setNewTicket({ ...newTicket, department: e.target.value, categoryId: '' })}
                  style={{ width: '100%', padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none' }}>
                  {(depts.length > 0 ? depts : [{ department: 'IT', label: 'IT Support', icon: '🖥️' }, { department: 'STUDENT_SERVICES', label: 'Student Services', icon: '🎓' }, { department: 'FACILITIES', label: 'Facilities', icon: '🏛️' }, { department: 'HR', label: 'HR & Admin', icon: '👥' }])
                    .map((d: any) => <option key={d.department} value={d.department}>{`${d.icon || ''} ${d.label}`.trim()}</option>)}
                </select>
              </div>
              <div>
                <div style={{ fontSize: 11, fontFamily: MONO, color: '#94A3B8', marginBottom: 5 }}>PRIORITY</div>
                <select value={newTicket.priority}
                  onChange={e => setNewTicket({ ...newTicket, priority: e.target.value })}
                  style={{ width: '100%', padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none' }}>
                  {['LOW', 'MEDIUM', 'HIGH', 'CRITICAL'].map(o => <option key={o} value={o}>{o}</option>)}
                </select>
              </div>
            </div>

            {(() => {
              const deptRoots = categories.filter((c: any) => !c.parentId && (!c.department || c.department === newTicket.department))
              return deptRoots.length > 0 ? (
                <div style={{ marginBottom: 14 }}>
                  <div style={{ fontSize: 11, fontFamily: MONO, color: '#94A3B8', marginBottom: 5 }}>CATEGORY <span style={{ color: '#CBD5E1' }}>(optional)</span></div>
                  <select value={newTicket.categoryId} onChange={e => setNewTicket({ ...newTicket, categoryId: e.target.value })}
                    style={{ width: '100%', padding: '10px 12px', border: '1px solid #E2E8F0', borderRadius: 8, fontSize: 13, fontFamily: FONT, outline: 'none' }}>
                    <option value=''>— Select a category —</option>
                    {deptRoots.map((root: any) => {
                      const subs = categories.filter((c: any) => c.parentId === root.id)
                      const prefix = root.icon ? root.icon + ' ' : ''
                      // No sub-categories → root is directly selectable (flat option)
                      if (subs.length === 0) {
                        return <option key={root.id} value={root.id}>{prefix}{root.name}</option>
                      }
                      // Has sub-categories → group header only, children are selectable
                      return (
                        <optgroup key={root.id} label={`${prefix}${root.name}`}>
                          {subs.map((sub: any) => (
                            <option key={sub.id} value={sub.id}>↳ {sub.name}</option>
                          ))}
                        </optgroup>
                      )
                    })}
                  </select>
                </div>
              ) : null
            })()}

            <div style={{ marginBottom: 20 }}>
              <div style={{ fontSize: 11, fontFamily: MONO, color: '#94A3B8', marginBottom: 5 }}>
                ATTACHMENTS <span style={{ color: '#CBD5E1' }}>(optional)</span>
                {storageConfig.allowedExtensions.length > 0 && (
                  <span style={{ marginLeft: 8, color: '#94A3B8' }}>· {storageConfig.allowedExtensions.join(', ')} · max {storageConfig.maxFileSizeMb} MB</span>
                )}
              </div>
              <label style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '10px 14px', border: '1px dashed #CBD5E1', borderRadius: 8, cursor: 'pointer', background: '#F8FAFC' }}>
                <span style={{ fontSize: 18 }}>📎</span>
                <span style={{ fontSize: 13, color: '#64748B' }}>{attachFiles.length > 0 ? `${attachFiles.length} file(s) selected` : 'Click to attach files…'}</span>
                <input type='file' multiple
                  accept={storageConfig.allowedExtensions.map(e => `.${e}`).join(',')}
                  style={{ display: 'none' }}
                  onChange={e => setAttachFiles(Array.from(e.target.files ?? []))}
                />
              </label>
              {attachFiles.length > 0 && (
                <div style={{ marginTop: 8, display: 'flex', flexWrap: 'wrap', gap: 6 }}>
                  {attachFiles.map((f, i) => (
                    <span key={i} style={{ fontSize: 11, background: '#EFF6FF', color: '#2563EB', padding: '3px 10px', borderRadius: 5, display: 'flex', alignItems: 'center', gap: 6 }}>
                      {f.name}
                      <button onClick={() => setAttachFiles(p => p.filter((_, j) => j !== i))} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#94A3B8', fontSize: 13, lineHeight: 1, padding: 0 }}>×</button>
                    </span>
                  ))}
                </div>
              )}
            </div>

            <div style={{ display: 'flex', gap: 10 }}>
              <button onClick={() => setShowNewTicket(false)} style={{ flex: 1, padding: 11, border: '1px solid #E2E8F0', borderRadius: 8, background: 'white', fontSize: 13, cursor: 'pointer', color: '#64748B' }}>Cancel</button>
              <button onClick={submitNewTicket} disabled={submitting} style={{ flex: 2, padding: 11, background: '#2563EB', color: 'white', border: 'none', borderRadius: 8, fontSize: 13, fontWeight: 700, cursor: 'pointer' }}>
                {submitting ? 'Creating…' : 'Create Ticket'}
              </button>
            </div>
          </div>
        </div>
      )}

      {toast && (
        <div style={{ position: 'fixed', bottom: 24, left: '50%', transform: 'translateX(-50%)', background: '#0F172A', color: 'white', padding: '12px 24px', borderRadius: 12, fontSize: 13, fontWeight: 600, zIndex: 200, boxShadow: '0 8px 24px rgba(0,0,0,0.2)' }}>{toast}</div>
      )}
    </div>
  )
}
